import{_ as t,o,c as n,ag as a}from"./chunks/framework.CpPsmr6h.js";const f=JSON.parse('{"title":"TunnelBox Registration","description":"","frontmatter":{},"headers":[],"relativePath":"docs/tunnelbox.md","filePath":"docs/tunnelbox.md","lastUpdated":1771868171000}'),i={name:"docs/tunnelbox.md"};function r(l,e,s,c,h,u){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="tunnelbox-registration" tabindex="-1">TunnelBox Registration <a class="header-anchor" href="#tunnelbox-registration" aria-label="Permalink to &quot;TunnelBox Registration&quot;">​</a></h1><p>This guide helps first-time users activate a TunnelBox device.</p><h2 id="before-you-start" tabindex="-1">Before You Start <a class="header-anchor" href="#before-you-start" aria-label="Permalink to &quot;Before You Start&quot;">​</a></h2><p>Make sure you have:</p><ul><li>A TunnelBox device with power adapter</li><li>Ethernet access to your router/network</li><li>A browser and internet connection</li><li>An account at <a href="https://console.tunnelbox.net" target="_blank" rel="noreferrer">console.tunnelbox.net</a></li></ul><h2 id="step-1-connect-hardware" tabindex="-1">Step 1: Connect Hardware <a class="header-anchor" href="#step-1-connect-hardware" aria-label="Permalink to &quot;Step 1: Connect Hardware&quot;">​</a></h2><ol><li>Connect the TunnelBox to power.</li><li>Connect Ethernet from TunnelBox to your router or switch.</li><li>Wait for the device to boot.</li></ol><h2 id="step-2-sign-in-to-the-console" tabindex="-1">Step 2: Sign In to the Console <a class="header-anchor" href="#step-2-sign-in-to-the-console" aria-label="Permalink to &quot;Step 2: Sign In to the Console&quot;">​</a></h2><ol><li>Open <a href="https://console.tunnelbox.net" target="_blank" rel="noreferrer">console.tunnelbox.net</a>.</li><li>Create an account or sign in.</li></ol><h2 id="step-3-activate-the-device" tabindex="-1">Step 3: Activate the Device <a class="header-anchor" href="#step-3-activate-the-device" aria-label="Permalink to &quot;Step 3: Activate the Device&quot;">​</a></h2><ol><li>Open the dashboard.</li><li>Click <code>Activate TunnelBox</code>.</li><li>Enter the device details requested by the wizard.</li><li>Confirm activation.</li></ol><h2 id="step-4-verify-online-status" tabindex="-1">Step 4: Verify Online Status <a class="header-anchor" href="#step-4-verify-online-status" aria-label="Permalink to &quot;Step 4: Verify Online Status&quot;">​</a></h2><p>After activation, check that the device appears as:</p><ul><li><code>Online</code> or <code>Connected</code></li><li>Ready for domain and route configuration</li></ul><h2 id="common-first-run-checks" tabindex="-1">Common First-Run Checks <a class="header-anchor" href="#common-first-run-checks" aria-label="Permalink to &quot;Common First-Run Checks&quot;">​</a></h2><ul><li>If the device is offline, confirm Ethernet is connected.</li><li>If activation fails, refresh and retry after 1-2 minutes.</li><li>If still blocked, use the <a href="/tunnelbox.net/docs/troubleshooting">Troubleshooting</a> guide.</li></ul>',16)])])}const p=t(i,[["render",r]]);export{f as __pageData,p as default};
